function validatorPubkeyHashTreeRoot(bytes memory pubkey) internal view returns (bytes32 root) {
        if (pubkey.length != VALIDATOR_PUBKEY_LENGTH) {
            InvalidValidatorPubkeyLength.selector.revertWith();
        }
        assembly ("memory-safe") {
            let result := staticcall(gas(), SHA256, add(pubkey, 32), 0x40, 0x00, 0x20)
            if eq(result, 0) { revert(0, 0) }
            root := mload(0x00)
        }
    }

